+	chtun := tuntest.NewChannelTUN()
+
+	resolved := netip.MustParseAddr("203.0.113.5")
+	rslv := &flakyThenResolver{host: "hub.example.com", addr: resolved}
+	factory := func() (dnsresolve.Resolver, error) { return rslv, nil }
